    def single_pipeline(self, cur_device_id, start_date, end_date, dedup = True):
        dedup_pipeline = [
        {
            '$match': {
                'metadata.deviceId': cur_device_id, 
                'timestamp': {
                    '$gt': start_date, 
                    '$lte': end_date
                }
            }
        }, {
            '$project': {
                'metadata': 1, 
                'timestamp': 1, 
                'server_timestamp': 1, 
                'lynx_arrival_ts': 1,
                'measurements': '$$ROOT'
            }
        }, {
            '$sort': {
                'metadata.deviceId': 1, 
                'timestamp': 1, 
                'lynx_arrival_ts': -1
            }
        }, {
            '$group': {
                '_id': {
                    'timestamp': '$timestamp'
                }, 
                'doc': {
                    '$first': '$$ROOT'
                }
            }
        }, {
            '$replaceRoot': {
                'newRoot': '$doc'
            }
        }, {
            '$sort': {
                'timestamp': -1
            }
        }, {
            '$group': {
                '_id': '$metadata.deviceId', 
                'records': {
                    '$firstN': {
                        'input': '$$ROOT', 
                        'n': 100
                    }
                }
            }
        }, {
            '$project': {
                '_id': 0, 
                'deviceId': '$_id', 
                'records': 1
            }
        }
        ]

        pipeline2 = [
            {
                '$match': {
                    'metadata.deviceId': {
                        '$in': cur_device_id
                    }, 
                    'timestamp': {
                        '$gt': start_date, 
                        '$lte': end_date
                    }
                }
            }, {
                '$sort': {
                    'metadata.deviceId': 1, 
                    'timestamp': -1
                }
            }
        ]
        return dedup_pipeline if dedup else pipeline2
    
    def get_time_period(self, num_hours = 24):
        istart = random.randint(0, 24)
        start_date = self.start_date + datetime.timedelta(hours=istart)
        end_date = start_date + datetime.timedelta(hours=num_hours)
        return start_date, end_date

    def get_device_batch(self, num_ids = 100):
        # Ensure we don't go beyond the available device IDs
        max_start = max(0, len(self.all_device_ids) - num_ids)
        istart = random.randint(0, max_start) if max_start > 0 else 0
        deviceIds = self.all_device_ids[istart:istart + num_ids]
        return deviceIds

    ################################################################
    # Start defining tasks and assign a weight to it.
    # All tasks need the @task() notation.
    # Weights indicate the chance to execute, e.g. 1=1x, 5=5x, etc.
    # In locustfile-mimesis.py, the task weights 
    # have been parameterized too and dynamically passed in via Host
    # TODO Create any additional task functions here
    ################################################################
    @task(100)
    def _async_find(self):
        # Note that you don't pass in self despite the signature above
        tic = self.get_time();
        name = "single_device_timestamp"
        max_ids = int(self.args["max_ids"])
        max_hrs = int(self.args["num_hours"])
        logit = self.args["logit"] == "yes"
        start_datetime, end_datetime = self.get_time_period(max_hrs)
        try:
            # Get the record from the target collection now
            log_items, total_docs = self.single_device_query(max_ids, start_datetime, end_datetime)
            events.request.fire(request_type="mlocust", name=name, response_time=(self.get_time()-tic)*1000, response_length=0)
            if logit:
                self.logging_coll.insert_many(log_items)
        except Exception as e:
            events.request.fire(request_type="mlocust", name=name, response_time=(self.get_time()-tic)*1000, response_length=0, exception=e)
            # Add a sleep so we don't overload the system with exceptions
            time.sleep(5)

    @task(20)
    def _async_find_server(self):
        # Note that you don't pass in self despite the signature above
        tic = self.get_time();
        name = "single_device_server_timestamp"
        max_ids = int(self.args["max_ids"])
        max_hrs = int(self.args["num_hours"])
        logit = self.args["logit"] == "yes"
        start_datetime, end_datetime = self.get_time_period(max_hrs)
        try:
            # Get the record from the target collection now
            log_items, total_docs = self.single_device_server_query(max_ids, start_datetime, end_datetime)
            events.request.fire(request_type="mlocust", name=name, response_time=(self.get_time()-tic)*1000, response_length=0)
            if logit:
                self.logging_coll.insert_many(log_items)
        except Exception as e:
            events.request.fire(request_type="mlocust", name=name, response_time=(self.get_time()-tic)*1000, response_length=0, exception=e)
            # Add a sleep so we don't overload the system with exceptions
            time.sleep(5)

    def single_device_query(self, max_ids, start_datetime, end_datetime):
        reps = 10 # 10 FIXME #int(num_ids / max_ids)
        batch_records = []
        log_records = []
        dedup = True
        istart = 0
        for _ in range(reps):
            cur_ids = random.choice(self.all_device_ids)
            query = self.single_pipeline(cur_ids, start_datetime, end_datetime, dedup)
            if self.verbose:
                pprint.pprint(query)  # Uncomment for debugging
            ans = self.coll.aggregate(query, allowDiskUse=True)
            recs = []
            rec_sum = 0
            if self.verbose:
                for rec in ans:
                    batch_records.append(rec)
                    recs.append({"ts" : datetime.datetime.now(), "device" : rec['deviceId'], "count" : len(rec['records'])})
                    rec_sum += len(rec["records"])
                    print(f'Device: {rec["deviceId"]} - {len(rec["records"])} records')
                print("# ----- Sample Record: ")
                pprint.pprint(batch_records[0])
            istart += max_ids
            log_records.append({"qtype" : "timestamp", "ts" : datetime.datetime.now(), "start_date": start_datetime, "end_date": end_datetime, "rep" : _, "records" : recs})
        return log_records, rec_sum

    def single_device_server_query(self, max_ids, start_datetime, end_datetime):
        reps = 10 #10 FIXME#int(num_ids / max_ids)
        batch_records = []
        log_records = []
        dedup = True
        istart = 0
        for _ in range(reps):
            cur_ids = random.choice(self.all_device_ids)
            query = self.single_pipeline(cur_ids, start_datetime, end_datetime, dedup)
            query[0]["$match"]["server_timestamp"] =  query[0]["$match"]["timestamp"]
            del query[0]["$match"]["timestamp"]
            if self.verbose:
                pprint.pprint(query)  # Uncomment for debugging
            ans = self.coll.aggregate(query, allowDiskUse=True)
            recs = []
            rec_sum = 0
            if self.verbose:
                for rec in ans:
                    batch_records.append(rec)
                    recs.append({"ts" : datetime.datetime.now(), "device" : rec['deviceId'], "count" : len(rec['records'])})
                    rec_sum += len(rec["records"])
                    print(f'Device: {rec["deviceId"]} - {len(rec["records"])} records')
                print("# ----- Sample Record: ")
                pprint.pprint(batch_records[0])
            istart += max_ids
            log_records.append({"qtype" : "server_timestamp", "ts" : datetime.datetime.now(), "start_date": start_datetime, "end_date": end_datetime, "rep" : _, "records" : recs})
        return log_records, rec_sum

    
